create table public.task_feedback(id uuid primary key default gen_random_uuid(),task_id uuid not null references public.tasks(id) on delete cascade,owner_id uuid not null references public.profiles(id) on delete cascade,rating text not null check(rating in('positive','negative')),categories text[] not null default '{}',comment text check(char_length(comment)<=1000),suggested_correction text check(char_length(suggested_correction)<=1000),created_at timestamptz not null default now());
create index task_feedback_owner_idx on public.task_feedback(owner_id,created_at desc);create index task_feedback_task_idx on public.task_feedback(task_id);
create table public.task_reflections(task_id uuid primary key references public.tasks(id) on delete cascade,owner_id uuid not null references public.profiles(id) on delete cascade,outcome text not null check(outcome in('completed','partial','failed','blocked')),what_worked text[] not null default '{}',what_failed text[] not null default '{}',user_corrections text[] not null default '{}',reusable_preference_candidates text[] not null default '{}',created_at timestamptz not null default now());
alter table public.task_feedback enable row level security;alter table public.task_reflections enable row level security;revoke all on public.task_feedback,public.task_reflections from public,anon,authenticated;grant select,insert on public.task_feedback,public.task_reflections to authenticated;grant all on public.task_feedback,public.task_reflections to service_role;
create policy task_feedback_owner_select on public.task_feedback for select to authenticated using((select auth.uid())=owner_id);create policy task_feedback_owner_insert on public.task_feedback for insert to authenticated with check((select auth.uid())=owner_id and exists(select 1 from public.tasks t where t.id=task_id and t.owner_id=(select auth.uid())));
create policy task_reflections_owner_select on public.task_reflections for select to authenticated using((select auth.uid())=owner_id);
create policy task_reflections_owner_insert on public.task_reflections for insert to authenticated with check((select auth.uid())=owner_id and exists(select 1 from public.tasks t where t.id=task_id and t.owner_id=(select auth.uid())));
